import { Component, inject, OnInit } from '@angular/core';
import { RouterOutlet, RouterLink, RouterLinkActive, Router } from '@angular/router';
import { CommonModule, NgIf, NgFor } from '@angular/common'; 
import { NotificationCenterComponent } from '../../../shared/components/notification-center/notification-center.component';
// 🚀 AJOUT : Importation de votre service centralisé pour intercepter le signal de popup
import { NotificationService } from '../../../core/services/notification.service';

@Component({
  selector: 'app-recruiter-layout',
  standalone: true,
  imports: [RouterOutlet, RouterLink, RouterLinkActive, CommonModule, NgIf, NgFor, NotificationCenterComponent], 
  templateUrl: './recruiter-layout.component.html',
  styleUrls: ['./recruiter-layout.component.css'] 
})
export class RecruiterLayoutComponent implements OnInit {
  private router = inject(Router);
  // 🚀 AJOUT : Injection de votre service de gestion des alertes
  private notificationService = inject(NotificationService);
  
  recruiterName = 'Recruteur';
  
  // 🚀 AJOUT : Variable locale pour mémoriser et injecter l'objet candidat dans la modal HTML
  selectedDirectCandidate: any = null;

  ngOnInit() {
    const storedName = localStorage.getItem('name');
    if (storedName) {
      this.recruiterName = storedName;
    }

    // 🚀 AJOUT : Écouteur réactif permanent. Dès que le service reçoit les données de can3,
    // cette variable se remplit et fait apparaître la popup blanche par surimpression !
    this.notificationService.activeModalCandidate$.subscribe(candidate => {
      this.selectedDirectCandidate = candidate;
    });
  }

  // 🚀 AJOUT : Méthode liée au clic sur la croix (X) et le bouton Fermer pour vider l'écran
  closeModal() {
    this.notificationService.closeDirectModal();
  }

  onLogout() {
    localStorage.clear();
    this.router.navigate(['/login']);
  }
}
<div class="app-container">
  
  <!-- 🧭 SIDEBAR COMPLÈTE & PROFESSIONNELLE SÉCURISÉE -->
  <aside class="app-sidebar">
    <div class="sidebar-brand">
      <div class="logo-icon"><i class="bi bi-rocket-takeoff-fill"></i></div>
      <div class="logo-text">Tun<span>Job</span> Pro</div>
    </div>

    <div class="recruiter-profile-summary">
      <div class="avatar-circle"><i class="bi bi-building-fill"></i></div>
      <div class="profile-info">
        <h4 class="company-name">Espace Recruteur</h4>
        <span class="badge-status"><span class="dot"></span> Compte Vérifié</span>
      </div>
    </div>

    <nav class="sidebar-nav">
      <div class="nav-section-title">Recrutement</div>
      
      <a routerLink="/recruiter" routerLinkActive="active" [routerLinkActiveOptions]="{exact: true}" class="nav-link-item">
        <i class="bi bi-grid-1x2-fill"></i> Vue d'ensemble
      </a>
      
      <a routerLink="/recruiter/create-job" routerLinkActive="active" class="nav-link-item">
        <i class="bi bi-plus-circle-fill"></i> Publier une offre
      </a>
      
      <a routerLink="/recruiter/job-manage" routerLinkActive="active" class="nav-link-item">
        <i class="bi bi-briefcase-fill"></i> Gérer mes annonces
      </a>
      
      <a routerLink="/recruiter/ats-pipeline" routerLinkActive="active" class="nav-link-item">
        <i class="bi bi-people-fill"></i> Suivi Candidats (ATS)
        <span class="nav-badge">14</span>
      </a>

      <div class="nav-section-title">Entreprise & Paramètres</div>
      
      <a routerLink="/recruiter/profile-settings" routerLinkActive="active" class="nav-link-item">
        <i class="bi bi-sliders"></i> Configuration Profil & Logo
      </a>

      <a (click)="onLogout()" class="nav-link-item logout-item">
        <i class="bi bi-box-arrow-left"></i> Quitter la session
      </a>
    </nav>
  </aside>

  <!-- 💻 ZONE DE CONTENU PRINCIPALE DYNAMIQUE -->
  <main class="app-main">
    <header class="app-header">
      <div class="header-welcome">
        <h2>Bienvenue, <span class="highlight">{{ recruiterName }}</span> 👋</h2>
        <p>Voici l'état actuel de vos campagnes de recrutement en Tunisie.</p>
      </div>

      <div class="header-actions">
        <button routerLink="/recruiter/create-job" class="btn-quick-add">
          <i class="bi bi-plus"></i> Nouvelle Annonce
        </button>

        <!-- 🚀 INJECTION DU CENTRE DE NOTIFICATIONS AUTONOME & PARTAGÉ -->
        <app-notification-center></app-notification-center>
        
      </div>
    </header>

    <!-- Zone d'injection principale pour les formulaires et listes -->
    <div class="content-body">
      <router-outlet></router-outlet>
    </div>

  </main>
</div>
